import { writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain';

let currentGame = null;
export const gameStore = writable(null);

export function getGame() {
  return currentGame;
}

export function initGame(sudokuGrid) {
  const sudoku = createSudoku(sudokuGrid);
  currentGame = createGame({ sudoku });
  gameStore.set(currentGame);
  return currentGame;
}

export function resetGame(sudokuGrid) {
  return initGame(sudokuGrid);
}